"""Модель конфигурации проекта (config.json): только базовое описание и сырые секции."""from __future__ import annotationsfrom dataclasses import dataclass, fieldfrom pathlib import Pathfrom typing import Anyfrom src.modules.project.project_paths import ProjectPathsfrom src.modules.project.sections import (    DiscoveryConfig,    ExtractConfig,    ImageProcessingConfig,    MarkdownConfig,    PipelineConfig,    TaggingConfig,)# Ключи верхнего уровня config.json (единый источник правды)PROJECT_CONFIG_KEYS = (    "project",    "discovery",    "extract",    "image_processing",    "markdown",    "tagging",    "pipeline",)@dataclassclass ProjectConfig:    """Конфигурация одного проекта (config.json). Базовая модель: paths + секции discovery, extract, image_processing, markdown, tagging, pipeline."""    paths: ProjectPaths    discovery: dict[str, Any] = field(default_factory=lambda: {"recursive_search": True})    extract: dict[str, Any] = field(default_factory=dict)    image_processing: dict[str, Any] = field(default_factory=ImageProcessingConfig.get_default)    markdown: dict[str, Any] = field(default_factory=MarkdownConfig.get_default)    tagging: dict[str, Any] = field(default_factory=TaggingConfig.get_default)    pipeline: dict[str, Any] = field(default_factory=PipelineConfig.get_default)    @property    def project_root(self) -> Path:        """Корень проекта (paths.root)."""        return self.paths.root    @staticmethod    def create_default(project_root: Path) -> ProjectConfig:        """Создаёт конфиг со значениями по умолчанию для заданного корня проекта."""        paths = ProjectPaths.from_root(project_root)        return ProjectConfig(            paths=paths,            discovery=dict(DiscoveryConfig.get_default()),            extract=dict(ExtractConfig.get_default()),            image_processing=dict(ImageProcessingConfig.get_default()),            markdown=dict(MarkdownConfig.get_default()),            tagging=dict(TaggingConfig.get_default()),            pipeline=dict(PipelineConfig.get_default()),        )    @staticmethod    def create_default_dict() -> dict[str, Any]:        """Словарь умолчаний для config.json (project, discovery, extract, image_processing, pipeline). Для использования при отсутствии файла."""        return {            "project": {},            "discovery": DiscoveryConfig.get_default(),            "extract": ExtractConfig.get_default(),            "image_processing": ImageProcessingConfig.get_default(),            "markdown": MarkdownConfig.get_default(),            "tagging": TaggingConfig.get_default(),            "pipeline": PipelineConfig.get_default(),        }